import torch
import torch.nn as nn
from torchdiffeq import odeint_adjoint as odeint


class VelocityField(nn.Module):
    """Unconstrained velocity field v_theta(z, t)."""
    def __init__(self, dim: int, hidden: int = 256, n_layers: int = 3):
        super().__init__()
        layers = [nn.Linear(dim + 1, hidden), nn.Tanh()]
        for _ in range(n_layers - 1):
            layers += [nn.Linear(hidden, hidden), nn.Tanh()]
        layers.append(nn.Linear(hidden, dim))
        self.net = nn.Sequential(*layers)

    def forward(self, t: torch.Tensor, z: torch.Tensor) -> torch.Tensor:
        # t is a scalar; broadcast to (B, 1)
        t_vec = t.expand(z.size(0), 1)
        return self.net(torch.cat([z, t_vec], dim=-1))


class CNF(nn.Module):
    def __init__(self, dim: int):
        super().__init__()
        self.vf = VelocityField(dim)

    def forward(
        self,
        z0: torch.Tensor,   # (B, D) noise
        t_span: torch.Tensor = None,  # integration range
    ) -> torch.Tensor:
        if t_span is None:
            t_span = torch.tensor([0.0, 1.0])
        # odeint_adjoint uses adjoint method for memory-efficient backprop
        traj = odeint(self.vf, z0, t_span, method="dopri5", rtol=1e-5, atol=1e-5)
        return traj[-1]   # z(T)
